class MurderWorld(World):
    """
    The MurderWorld is a World that contains clues and suspects, and has rules for determining which suspect is the killer.
    """

    def __init__(self, clues: List[Clue], suspects: List[Suspect]):
        super().__init__(clues, suspects)

    @property
    def clues(self) -> List[Clue]:
        return self._clues

    @property
    def suspects(self) -> List[Suspect]:
        return self._suspects

    def solve(self) -> ClueSolution:
        """
        Solves the murder and returns the ClueSolution.

