        """
        return self._solve()

    def _solve(self) -> ClueSolution:
        """
        Solves the murder and returns the ClueSolution.

        :return: The ClueSolution.
        """
        # There is only one solution
        solution = ClueSolution(self.suspects, self.clues)
        # Loop through the suspects
        for suspect in self.suspects:
            # If the suspect is the killer, return the ClueSolution
            if suspect.is_killer():
                return solution
        return solution

    def _is_suspect_the_killer(self, suspect: Suspect) -> bool:
        """
        Returns whether or not the suspect is the killer.

        :param suspect: The suspect.
        :return: Whether or not the suspect is the killer.
        """
        # Loop through the clues
        for clue in self.clues:
            # If the clue is satisfied, return whether or not the suspect is the killer
            if clue.is_satisfied(suspect):
                if suspect.is_killer():
                    return True
                return self._is_suspect_the_killer(suspect)
